class AttendancePage(QtWidgets.QWidget):
    """
    Full Attendance page — slots into the Industrial Attachment sub-tab stack
    (or stackedWidget_2 index 2).

    Layout
    ──────
    Left scroll area
      • Page header + breadcrumb
      • 5 stat cards (Total / Present / Late / Absent / Attendance Rate)
      • Filter row (Date / Department / Status / Search / Actions)
      • Attendance Records section: table + pagination
      • Bottom analytics row: overview donut | trend | dept bars | punctuality donut
    Right panel (fixed 280px)
      • Attachee Details card (selected row)
      • Quick Actions
    """

    def __init__(self, parent=None):
        super().__init__(parent)
        self.setObjectName("Attendance_Page")
        self.setStyleSheet(f"background:{_BG};")
        self._records = list(SAMPLE_ATTENDANCE)
        self._build_ui()
        self._populate_table()
