    # ──────────────────────────────────────────────────────────────────────────
    # TABLE POPULATION
    # ──────────────────────────────────────────────────────────────────────────
    def _populate_table(self, data: list = None):
        rows = data if data is not None else self._records
        self.table.setRowCount(0)
        for i, rec in enumerate(rows):
            (num, name, reg_no, institution, dept, supervisor, start_date, end_date,
             check_in, check_out, total_hours, week_att, status, remarks) = rec
            self.table.insertRow(i)
            self.table.setRowHeight(i, 48)

            self._set_item(i, 0, str(i + 1))

            att_w = QtWidgets.QWidget()
            aw_hl = QtWidgets.QHBoxLayout(att_w)
            aw_hl.setContentsMargins(6, 0, 6, 0); aw_hl.setSpacing(8)
            colour = AVATAR_COLOURS[i % len(AVATAR_COLOURS)]
            aw_hl.addWidget(_AvatarCircle(name, colour))
            name_lbl = QtWidgets.QLabel(name)
            name_lbl.setStyleSheet(f"color:{_TEXT_DARK};font-size:12px;font-weight:600;")
            aw_hl.addWidget(name_lbl)
            aw_hl.addStretch()
            self.table.setCellWidget(i, 1, att_w)

            self._set_item(i, 2, reg_no)
            self._set_item(i, 3, dept)
            self._set_item(i, 4, supervisor)
            self._set_item(i, 5, check_in)
            self._set_item(i, 6, check_out)
            self._set_item(i, 7, total_hours)

            fg, bg = STATUS_COLOURS.get(status, (_TEXT_MID, "#f3f4f6"))
            self.table.setCellWidget(i, 8, self._centre(_Badge(status, fg, bg)))
            self._set_item(i, 9, remarks)
            self.table.setCellWidget(i, 10, self._action_widget(i))

        count = len(rows)
        self.showing_lbl.setText(
            f"Showing 1 to {min(10, count)} of {count} records")

    def _set_item(self, row, col, text):
        it = QtWidgets.QTableWidgetItem(text)
        it.setFlags(it.flags() & ~Qt.ItemFlag.ItemIsEditable)
        self.table.setItem(row, col, it)

    @staticmethod
    def _centre(widget) -> QtWidgets.QWidget:
        w = QtWidgets.QWidget()
        hl = QtWidgets.QHBoxLayout(w)
        hl.addWidget(widget)
        hl.setAlignment(Qt.AlignmentFlag.AlignLeft | Qt.AlignmentFlag.AlignVCenter)
        hl.setContentsMargins(6, 0, 0, 0)
        return w

    def _action_widget(self, row: int) -> QtWidgets.QWidget:
        w = QtWidgets.QWidget()
        hl = QtWidgets.QHBoxLayout(w)
        hl.setContentsMargins(4, 0, 4, 0); hl.setSpacing(4)
        for ico, tip, col, slot in [
            ("👁", "View",   "#64748b", lambda _, r=row: self._show_details(r)),
            ("✏",  "Edit",   "#2563eb", lambda _, r=row: self._on_edit(r)),
            ("🗑",  "Delete", "#dc2626", lambda _, r=row: self._on_delete(r)),
        ]:
            b = QtWidgets.QPushButton(ico)
            b.setFixedSize(22, 22)
            b.setToolTip(tip)
            b.setCursor(QtGui.QCursor(Qt.CursorShape.PointingHandCursor))
            b.setStyleSheet(f"""
                QPushButton {{
                    background:{col}22; color:{col};
                    border:1px solid {col}44;
                    border-radius:5px; font-size:10px;
                }}
                QPushButton:hover {{ background:{col}44; }}
            """)
            b.clicked.connect(slot)
            hl.addWidget(b)
        hl.addStretch()
        return w

    # ──────────────────────────────────────────────────────────────────────────
    # RIGHT PANEL — ATTACHEE DETAILS
    # ──────────────────────────────────────────────────────────────────────────
    def _show_details(self, row: int):
        if row >= len(self._records):
            return
        (num, name, reg_no, institution, dept, supervisor, start_date, end_date,
         check_in, check_out, total_hours, week_att, status, remarks) = self._records[row]
        self._selected_row = row

        while self._dd_vl.count():
            item = self._dd_vl.takeAt(0)
            if item.widget():
                item.widget().deleteLater()

        hdr_lbl = QtWidgets.QLabel("Attachee Details")
        hdr_lbl.setStyleSheet(f"color:{_TEXT_DARK};font-size:13px;font-weight:bold;"
                              "font-family:'Segoe UI',Arial;")
        self._dd_vl.addWidget(hdr_lbl)

        colour = AVATAR_COLOURS[row % len(AVATAR_COLOURS)]
        ico_row = QtWidgets.QHBoxLayout()
        ico_row.setAlignment(Qt.AlignmentFlag.AlignCenter)
        ico_row.addWidget(_AvatarCircle(name, colour, size=64))
        self._dd_vl.addLayout(ico_row)

        tl = QtWidgets.QLabel(name)
        tl.setAlignment(Qt.AlignmentFlag.AlignCenter)
        tl.setWordWrap(True)
        tl.setStyleSheet(f"color:{_TEXT_DARK};font-size:14px;font-weight:bold;"
                         "font-family:'Segoe UI',Arial;")
        self._dd_vl.addWidget(tl)

        sfg, sbg = STATUS_COLOURS.get(status, (_TEXT_MID, "#f3f4f6"))
        st_badge = _Badge(status, sfg, sbg)
        st_row = QtWidgets.QHBoxLayout()
        st_row.setAlignment(Qt.AlignmentFlag.AlignCenter)
        st_row.addWidget(st_badge)
        self._dd_vl.addLayout(st_row)

        dv = QtWidgets.QFrame()
        dv.setFrameShape(QtWidgets.QFrame.Shape.HLine)
        dv.setStyleSheet(f"color:{_BORDER};")
        self._dd_vl.addWidget(dv)

        details = [
            ("Registration No.", reg_no),
            ("Institution",      institution),
            ("Department",       dept),
            ("Supervisor",       supervisor),
            ("Start Date",       start_date),
            ("End Date",         end_date),
            ("Check-In Time",    check_in),
            ("Check-Out Time",   check_out),
            ("Total Hours Today", total_hours),
            ("Week Attendance",  week_att),
        ]
        for d_lbl, d_val in details:
            row_hl = QtWidgets.QHBoxLayout(); row_hl.setSpacing(6)
            ll = QtWidgets.QLabel(d_lbl)
            ll.setFixedWidth(115)
            ll.setStyleSheet(f"color:{_TEXT_GREY};font-size:10px;")
            vw = QtWidgets.QLabel(d_val)
            vw.setWordWrap(True)
            vw.setStyleSheet(f"color:{_TEXT_DARK};font-size:10px;font-weight:600;")
            row_hl.addWidget(ll); row_hl.addWidget(vw, stretch=1)
            self._dd_vl.addLayout(row_hl)

        st_row2 = QtWidgets.QHBoxLayout(); st_row2.setSpacing(6)
        st_lbl = QtWidgets.QLabel("Status Today")
        st_lbl.setFixedWidth(115)
        st_lbl.setStyleSheet(f"color:{_TEXT_GREY};font-size:10px;")
        st_val = _Badge(status, sfg, sbg)
        st_row2.addWidget(st_lbl); st_row2.addWidget(st_val); st_row2.addStretch()
        self._dd_vl.addLayout(st_row2)

        rm_row = QtWidgets.QHBoxLayout(); rm_row.setSpacing(6)
        rm_lbl = QtWidgets.QLabel("Remarks")
        rm_lbl.setFixedWidth(115)
        rm_lbl.setStyleSheet(f"color:{_TEXT_GREY};font-size:10px;")
        rm_val = QtWidgets.QLabel(remarks)
        rm_val.setWordWrap(True)
        rm_val.setStyleSheet(f"color:{_TEXT_DARK};font-size:10px;font-weight:600;")
        rm_row.addWidget(rm_lbl); rm_row.addWidget(rm_val, stretch=1)
        self._dd_vl.addLayout(rm_row)

        vfp_btn = QtWidgets.QPushButton("View Full Profile")
        vfp_btn.setFixedHeight(34)
        vfp_btn.setCursor(QtGui.QCursor(Qt.CursorShape.PointingHandCursor))
        vfp_btn.setStyleSheet(f"""
            QPushButton {{
                background:{_ACCENT}; color:{_WHITE}; border:none;
                border-radius:6px; font-size:12px; font-weight:bold;
            }}
            QPushButton:hover {{ background:#4a60ee; }}
        """)
        vfp_btn.clicked.connect(lambda _, r=row: self._on_view(r))
        self._dd_vl.addSpacing(4)
        self._dd_vl.addWidget(vfp_btn)

    # ──────────────────────────────────────────────────────────────────────────
    # SLOTS
    # ──────────────────────────────────────────────────────────────────────────
    def _apply_filters(self):
        text = self.search_edit.text().lower()
        dept_f = self._dept_combo.currentText()
        status_f = self._status_combo.currentText()
        results = []
        for rec in self._records:
            (num, name, reg_no, institution, dept, supervisor, start_date, end_date,
             check_in, check_out, total_hours, week_att, status, remarks) = rec
            if dept_f != "All Departments" and dept != dept_f: continue
            if status_f != "All Statuses" and status != status_f: continue
            if text and not any(text in v.lower() for v in
                                (name, reg_no, dept, supervisor)):
                continue
            results.append(rec)
        self._populate_table(results)

    def _on_row_click(self, row, col):
        self._show_details(row)

    def _on_add(self):
        dlg = RecordAttendanceDialog(self)
        dlg.attendance_saved.connect(self._append_record)
        dlg.exec()

    def _append_record(self, data: dict):
        from datetime import date
        new_num = len(self._records) + 1
        reg_no = f"REG/2025/{new_num:03d}"
        self._records.insert(0, (
            new_num, data["name"], reg_no, "—", data["department"],
            data["supervisor"], date.today().strftime("%d %b %Y"), "—",
            data["check_in"], data["check_out"], "0h 00m", "1 / 1 days",
            data["status"], data["remarks"]
        ))
        self._apply_filters()
        QtWidgets.QMessageBox.information(
            self, "Attendance Recorded",
            f"✅  Attendance for '{data['name']}' has been recorded successfully."
        )

    def _on_view(self, row: int):
        if row >= len(self._records): return
        r = self._records[row]
        QtWidgets.QMessageBox.information(
            self, "Attachee Full Profile",
            f"<b>{r[1]}</b><br>Reg. No: {r[2]}<br>Institution: {r[3]}<br>"
            f"Department: {r[4]}<br>Supervisor: {r[5]}<br>"
            f"Start: {r[6]}  •  End: {r[7]}<br>"
            f"Check-In: {r[8]}  •  Check-Out: {r[9]}<br>"
            f"Total Hours: {r[10]}<br>Week Attendance: {r[11]}<br>"
            f"Status: {r[12]}<br>Remarks: {r[13]}"
        )

    def _on_edit(self, row: int):
        if row >= len(self._records): return
        r = self._records[row]
        dlg = RecordAttendanceDialog(self, data={
            "name": r[1], "department": r[4], "supervisor": r[5],
            "check_in": r[8], "check_out": r[9], "status": r[12], "remarks": r[13],
        })
        dlg.attendance_saved.connect(lambda d, rr=row: self._save_edit(rr, d))
        dlg.exec()

    def _on_edit_selected(self):
        row = getattr(self, "_selected_row", DEFAULT_SELECTED_INDEX)
        self._on_edit(row)

    def _save_edit(self, row: int, data: dict):
        old = self._records[row]
        self._records[row] = (
            old[0], data["name"], old[2], old[3], data["department"],
            data["supervisor"], old[6], old[7], data["check_in"], data["check_out"],
            old[10], old[11], data["status"], data["remarks"]
        )
        self._apply_filters()
        self._show_details(row)

    def _on_delete(self, row: int):
        if row >= len(self._records): return
        name = self._records[row][1]
        reply = QtWidgets.QMessageBox.question(
            self, "Delete Record",
            f"Delete the attendance record for <b>{name}</b>? This cannot be undone.",
            QtWidgets.QMessageBox.StandardButton.Yes |
            QtWidgets.QMessageBox.StandardButton.No,
            QtWidgets.QMessageBox.StandardButton.No,
        )
        if reply == QtWidgets.QMessageBox.StandardButton.Yes:
            self._records.pop(row)
            self._apply_filters()

    def _on_filter_menu(self):
        QtWidgets.QMessageBox.information(
            self, "Advanced Filters",
            "Advanced filter panel will be available in the next sprint."
        )

    def _on_export(self):
        QtWidgets.QMessageBox.information(
            self, "Export",
            "Export functionality will be connected in the next sprint."
        )

    def _on_placeholder(self):
        QtWidgets.QMessageBox.information(
            self, "Coming Soon",
            "This feature will be available in the next sprint."
        )